<?php declare(strict_types=1); namespace App\Http\Controllers\Btaq; use App\Http\Controllers\Controller; use App\Models\BtaqSession; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; final class BtaqVerificationController extends Controller{public function index(){return view('btaq.verifications.index',['sessions'=>BtaqSession::where('status','submitted')->latest()->paginate(15)]);} public function verify(Request $r,BtaqSession $btaqSession){DB::transaction(fn()=>tap(BtaqSession::lockForUpdate()->findOrFail($btaqSession->id),function($s)use($r){abort_if($s->status!=='submitted',422);$s->update(['status'=>'verified','verified_by'=>auth()->id(),'verified_at'=>now(),'verification_notes'=>$r->input('verification_notes')]);activity('btaq')->performedOn($s)->event('btaq.session.verified')->log('Jurnal BTAQ diverifikasi');}));return back()->with('status','Jurnal BTAQ diverifikasi.');} public function reject(Request $r,BtaqSession $btaqSession){$d=$r->validate(['rejection_reason'=>'required|string']);DB::transaction(fn()=>tap(BtaqSession::lockForUpdate()->findOrFail($btaqSession->id),function($s)use($d){abort_if($s->status!=='submitted',422);$s->update(['status'=>'rejected','rejected_by'=>auth()->id(),'rejected_at'=>now(),'rejection_reason'=>$d['rejection_reason']]);activity('btaq')->performedOn($s)->event('btaq.session.rejected')->log('Jurnal BTAQ diminta perbaikan');}));return back()->with('status','Jurnal BTAQ diminta perbaikan.');}}
